import{_ as e,o as i,c as t,ae as s}from"./chunks/framework.Co1PSFSm.js";const l="/assets/image.BxaM69FD.png",g=JSON.parse('{"title":"在 macOS 上安装 Whisper 进行语音识别","description":"","frontmatter":{"title":"在 macOS 上安装 Whisper 进行语音识别"},"headers":[],"relativePath":"blog/macOS安装whisper进行语音识别.md","filePath":"blog/macOS安装whisper进行语音识别.md"}'),r={name:"blog/macOS安装whisper进行语音识别.md"};function h(o,a,n,p,d,c){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="在-macos-上安装-whisper-进行语音识别" tabindex="-1">在 macOS 上安装 Whisper 进行语音识别 <a class="header-anchor" href="#在-macos-上安装-whisper-进行语音识别" aria-label="Permalink to &quot;在 macOS 上安装 Whisper 进行语音识别&quot;">​</a></h1><h2 id="第一步-安装-homebrew" tabindex="-1">第一步：安装 Homebrew <a class="header-anchor" href="#第一步-安装-homebrew" aria-label="Permalink to &quot;第一步：安装 Homebrew&quot;">​</a></h2><p>Homebrew 是一个开源的软件包管理工具，非常适合在 macOS 系统上使用。</p><blockquote><p>如果您已经安装了 Homebrew，可以跳过此步骤。</p></blockquote><h3 id="安装过程" tabindex="-1">安装过程 <a class="header-anchor" href="#安装过程" aria-label="Permalink to &quot;安装过程&quot;">​</a></h3><ol><li>访问 <a href="https://brew.sh/" target="_blank" rel="noreferrer">Homebrew 官网</a></li><li>复制官网提供的安装命令</li><li>粘贴到终端中并回车执行</li></ol><p>安装前系统会向您确认安装内容，再次回车即可开始安装。</p><blockquote><p><strong>注意</strong>：下载过程可能比较耗时，请耐心等待。</p></blockquote><h3 id="配置环境变量" tabindex="-1">配置环境变量 <a class="header-anchor" href="#配置环境变量" aria-label="Permalink to &quot;配置环境变量&quot;">​</a></h3><p>安装完成后，您需要配置环境变量，否则执行命令时可能会报错。</p><p>配置环境变量很简单，只需执行终端提示的脚本命令即可：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例命令，请以官网最新提示为准</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opt/homebrew/bin/brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shellenv)&quot;</span></span></code></pre></div><p>执行完成后，您就可以正常使用 brew 命令了。</p><blockquote><p>成功完成此步骤后，整个安装过程就完成了一大半。</p></blockquote><h2 id="第二步-下载-whisper-的语音模型" tabindex="-1">第二步：下载 Whisper 的语音模型 <a class="header-anchor" href="#第二步-下载-whisper-的语音模型" aria-label="Permalink to &quot;第二步：下载 Whisper 的语音模型&quot;">​</a></h2><p>官方提供了 tiny、base、small、medium、large 五种不同规格的语音模型。</p><table tabindex="0"><thead><tr><th>模型</th><th>适用场景</th><th>特点</th></tr></thead><tbody><tr><td>tiny</td><td>快速测试</td><td>最小</td></tr><tr><td>base</td><td>一般用途</td><td>小巧</td></tr><tr><td>small</td><td>一般用途</td><td>推荐</td></tr><tr><td>medium</td><td>高精度需求</td><td>较大</td></tr><tr><td>large</td><td>最高精度</td><td>最大</td></tr></tbody></table><p>对于一般用途，推荐选择 <strong>small</strong> 模型。虽然只有几百 MB，但中文识别准确度很高。</p><h3 id="下载模型" tabindex="-1">下载模型 <a class="header-anchor" href="#下载模型" aria-label="Permalink to &quot;下载模型&quot;">​</a></h3><ol><li>访问 Whisper 模型下载页面 (例如 <a href="https://huggingface.co/ggerganov/whisper.cpp" target="_blank" rel="noreferrer">huggingface.co/ggerganov/whisper.cpp</a>)</li><li>找到 <code>ggml-small.bin</code> 文件</li><li>点击下载</li></ol><p>下载完成后，请将模型文件保存在一个容易访问的目录中备用。</p><h2 id="第三步-安装-whisper" tabindex="-1">第三步：安装 Whisper <a class="header-anchor" href="#第三步-安装-whisper" aria-label="Permalink to &quot;第三步：安装 Whisper&quot;">​</a></h2><p>由于我们之前安装了 Homebrew，现在只需执行以下命令即可完成安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whisper</span></span></code></pre></div><blockquote><p><strong>注意</strong>：安装过程中可能会出现网络问题，可以重试或尝试使用代理。</p></blockquote><h2 id="如何使用-whisper" tabindex="-1">如何使用 Whisper <a class="header-anchor" href="#如何使用-whisper" aria-label="Permalink to &quot;如何使用 Whisper&quot;">​</a></h2><p>Whisper 官方提供了多种使用方式，下面介绍一种最简单的用法：<strong>whisper-server</strong>。</p><h3 id="启动-whisper-server" tabindex="-1">启动 Whisper Server <a class="header-anchor" href="#启动-whisper-server" aria-label="Permalink to &quot;启动 Whisper Server&quot;">​</a></h3><p>whisper-server 是官方自带的可视化界面，可以直接在浏览器中打开，操作方便。</p><p>执行以下命令启动服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whisper-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/ggml-small.bin</span></span></code></pre></div><blockquote><p><strong>重要</strong>：请将命令中的 <code>/path/to/ggml-small.bin</code> 替换为您在第二步中下载的语音模型文件的实际路径。</p></blockquote><p>例如，如果您的模型文件保存在 Downloads 文件夹中：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whisper-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Downloads/ggml-small.bin</span></span></code></pre></div><h3 id="使用界面" tabindex="-1">使用界面 <a class="header-anchor" href="#使用界面" aria-label="Permalink to &quot;使用界面&quot;">​</a></h3><p>命令执行成功后，服务会监听端口 <strong>9001</strong>。</p><p>在浏览器中打开 <code>http://localhost:9001</code> 即可看到界面。</p><p><img src="`+l+'" alt="alt text"></p><p>界面非常简洁，您需要做的所有事情包括：</p><ol><li>选择一个语音文件</li><li>选择需要的文件输出格式</li><li>点击 <strong>Submit</strong> 按钮</li></ol><h3 id="输出格式选项" tabindex="-1">输出格式选项 <a class="header-anchor" href="#输出格式选项" aria-label="Permalink to &quot;输出格式选项&quot;">​</a></h3><p>Whisper 支持多种输出格式：</p><ul><li><strong>TXT</strong> - 纯文本格式</li><li><strong>VTT</strong> - WebVTT 字幕格式</li><li><strong>SRT</strong> - 标准字幕格式</li><li><strong>JSON</strong> - JSON 格式</li><li><strong>CSV</strong> - CSV 表格格式</li></ul><h2 id="实际应用示例" tabindex="-1">实际应用示例 <a class="header-anchor" href="#实际应用示例" aria-label="Permalink to &quot;实际应用示例&quot;">​</a></h2><p>让我们用一个音频文件演示整个使用过程。</p><h3 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h3><ol><li>准备要转录的音频文件</li><li>启动 whisper-server</li><li>访问 <code>http://localhost:9001</code></li></ol><h3 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><ol><li>在界面上选择音频文件</li><li>选择输出格式（例如 SRT）</li><li>点击 Submit</li></ol><h3 id="结果验证" tabindex="-1">结果验证 <a class="header-anchor" href="#结果验证" aria-label="Permalink to &quot;结果验证&quot;">​</a></h3><ul><li>识别准确性通常很高</li><li>处理速度快</li><li>支持多种音频格式</li></ul><h3 id="与视频编辑软件结合" tabindex="-1">与视频编辑软件结合 <a class="header-anchor" href="#与视频编辑软件结合" aria-label="Permalink to &quot;与视频编辑软件结合&quot;">​</a></h3><p>生成的字幕文件可以导入到各种视频编辑软件中，例如剪映：</p><ol><li>导出 SRT 字幕文件</li><li>打开视频编辑软件（如剪映）</li><li>导入音频文件</li><li>导入生成的字幕文件</li><li>调整字幕样式和位置</li></ol><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>这种使用 Whisper 生成字幕的方法具有以下优点：</p><ul><li><strong>免费</strong>：无需付费使用</li><li><strong>准确</strong>：中文识别准确率高</li><li><strong>灵活</strong>：支持多种输出格式</li><li><strong>高效</strong>：处理速度快</li></ul><p>这种方式完美解决了普通用户自动生成字幕的需求。如果您觉得这个方法有用，请点赞关注我，我会持续分享更多实用技巧。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-安装过程中遇到网络问题怎么办" tabindex="-1">Q: 安装过程中遇到网络问题怎么办？ <a class="header-anchor" href="#q-安装过程中遇到网络问题怎么办" aria-label="Permalink to &quot;Q: 安装过程中遇到网络问题怎么办？&quot;">​</a></h3><p>A: 可以尝试重试，或使用网络加速工具。</p><h3 id="q-模型文件应该选择哪个" tabindex="-1">Q: 模型文件应该选择哪个？ <a class="header-anchor" href="#q-模型文件应该选择哪个" aria-label="Permalink to &quot;Q: 模型文件应该选择哪个？&quot;">​</a></h3><p>A: 对于一般用途，推荐 small 模型；对精度要求高可选择 medium 或 large。</p><h3 id="q-如何提高识别准确度" tabindex="-1">Q: 如何提高识别准确度？ <a class="header-anchor" href="#q-如何提高识别准确度" aria-label="Permalink to &quot;Q: 如何提高识别准确度？&quot;">​</a></h3><p>A: 选择更大的模型，或对原始音频进行降噪处理。</p>',65)])])}const u=e(r,[["render",h]]);export{g as __pageData,u as default};
